"""Init command for ctxcli."""

import asyncio
import os
from datetime import datetime
from typing import Annotated

import typer
from rich.console import Console

from context_surfaces.cli.ctxcli.config import (
    ConfigManager,
    ProfileConfig,
    ToolsCache,
    ToolSchema,
)
from context_surfaces.cli.ctxcli.constants import (
    DEFAULT_MCP_URL,
    DEFAULT_PROFILE_NAME,
    ENV_AGENT_KEY,
    ENV_MCP_URL,
)

console = Console()


def init_command(
    ctx: typer.Context,
    agent_key: Annotated[
        str | None,
        typer.Option(
            "--agent-key",
            help="Agent API key",
            envvar=ENV_AGENT_KEY,
        ),
    ] = None,
    mcp_url: Annotated[
        str | None,
        typer.Option(
            "--mcp-url",
            help=f"MCP server URL (default: {DEFAULT_MCP_URL})",
            envvar=ENV_MCP_URL,
        ),
    ] = None,
    profile: Annotated[
        str | None,
        typer.Option(
            "--profile",
            "-p",
            help="Profile name to initialize",
        ),
    ] = None,
) -> None:
    """Initialize ctxcli with an agent key.

    Fetches available tools from the MCP server and caches them locally.

    [bold]Examples:[/bold]
        ctxcli init
        ctxcli init --agent-key cs_agent_xxx
        ctxcli init --profile prod --mcp-url https://mcp.prod.example.com
    """
    # Get config manager from context or create new one
    config_manager = ctx.obj.get("config_manager") if ctx.obj else None
    if config_manager is None:
        config_manager = ConfigManager()

    # Determine profile name
    profile_name = profile or ctx.obj.get("profile") if ctx.obj else None
    if profile_name is None:
        profile_name = os.environ.get("CTXCLI_PROFILE", DEFAULT_PROFILE_NAME)

    # Interactive prompts if not provided
    if agent_key is None:
        agent_key = typer.prompt("Agent key")

    if mcp_url is None:
        mcp_url = typer.prompt(
            "MCP URL",
            default=DEFAULT_MCP_URL,
            show_default=True,
        )

    # Validate inputs
    if not agent_key:
        console.print("[bold red]Error:[/bold red] Agent key is required")
        raise typer.Exit(code=1)

    if not agent_key.startswith("cs_agent_"):
        console.print(
            "[bold yellow]Warning:[/bold yellow] Agent key doesn't start with 'cs_agent_'"
        )
        if not typer.confirm("Continue anyway?"):
            raise typer.Exit(code=0)

    # Fetch tools from MCP server
    console.print(f"\nConnecting to [cyan]{mcp_url}[/cyan]...")

    try:
        tools = asyncio.run(_fetch_tools(mcp_url, agent_key))
    except Exception as e:
        console.print(f"[bold red]Error:[/bold red] Failed to connect: {e}")
        raise typer.Exit(code=1) from e

    # Create profile config
    profile_config = ProfileConfig(
        mcp_url=mcp_url,
        agent_key=agent_key,
        tools_cache=ToolsCache(
            fetched_at=datetime.now(),
            tools=[
                ToolSchema(
                    name=tool.get("name", ""),
                    description=tool.get("description", ""),
                    input_schema=tool.get("inputSchema", {}),
                )
                for tool in tools
            ],
        ),
    )

    # Save configuration
    config_manager.set_profile(profile_name, profile_config)

    # Success message
    console.print(f"\n[green]✓[/green] Initialized profile '[bold]{profile_name}[/bold]'")
    console.print(f"  MCP URL: {mcp_url}")
    console.print(f"  Tools: {len(tools)} available")

    # Group and display entities
    from context_surfaces.cli.ctxcli.transformer import (
        group_commands_by_entity,
        transform_tool_name,
    )

    commands = [transform_tool_name(t.get("name", "")) for t in tools]
    grouped = group_commands_by_entity(commands)

    console.print(f"\n  Entities: {', '.join(sorted(grouped.keys()))}")
    console.print("\nRun [cyan]ctxcli[/cyan] to see available commands.")


async def _fetch_tools(mcp_url: str, agent_key: str) -> list[dict]:
    """Fetch tools list from MCP server.

    Args:
        mcp_url: MCP server URL
        agent_key: Agent API key

    Returns:
        List of tool definitions

    Raises:
        Exception: If connection fails
    """
    from context_surfaces.mcp_client import MCPClient

    async with MCPClient(mcp_url=mcp_url, agent_key=agent_key) as mcp:
        return await mcp.list_tools()

